import os, subprocess, sys
print("=" * 64, flush=True)
print("PDT-Lean verifier  ·  HARDENED build (fail-loud)  ·  11 Lean modules", flush=True)
print("If you do NOT see this banner as the first output, you pasted an old copy.", flush=True)
print("=" * 64, flush=True)
def sh(c, check=True, **k):
    # Additive hardening: stream the command, then stop LOUDLY on a nonzero exit
    # instead of silently marching on. On a successful run every step returns 0,
    # so this changes nothing; it only makes a failure visible (and names the stage).
    print("$", c, flush=True)
    r = subprocess.run(c, shell=True, **k)
    if check and r.returncode != 0:
        print("\n" + "=" * 60, flush=True)
        print("!!! STAGE FAILED (exit %d): %s" % (r.returncode, c), flush=True)
        print("!!! Stopping. Copy the ~15 lines above and send them for diagnosis.", flush=True)
        print("=" * 60, flush=True)
        raise SystemExit(r.returncode)
    return r
