THMS=['PDT.QM_from_Q', 'PDT.born_form', 'PDT.hermitian_real', 'PDT.born_nonneg_physical', 'PDT.disc_cubic', 'PDT.twentythree_weld', 'PDT.unit_norm_Q', 'PDT.dim_su3_su4', 'PDT.disc_quartic', 'PDT.prime_283', 'PDT.norm_2Q_sub_one', 'PDT.unit_norm_rhoQ', 'PDT.dim_su4', 'PDT.signature_3_1', 'PDT.det_M', 'PDT.congruence', 'PDT.signature_2_1', 'PDT.detMρ', 'PDT.congruenceρ', 'PDT.chsh_le_two_sqrt_two', 'PDT.chsh_saturates', 'PDT.isCHSH', 'PDT.chsh_comm_le_two', 'PDT.bell_gap', 'PDT.discr_cubic', 'PDT.discr_quartic', 'PDT.norm_Q', 'PDT.norm_ρ', 'PDT.traceForm_eq_M4', 'PDT.cubicQ_irreducible', 'PDT.quarticQ_irreducible']
check='import PdtQm\nimport PdtGolden\nimport PdtArithmetic\nimport PdtSignature\nimport PdtSignatureRho\nimport PdtTsirelson\nimport PdtBellClassical\nimport PdtDiscriminant\nimport PdtNorm\nimport PdtTraceForm\nimport PdtIrreducible\n'+"".join("#print axioms "+t+"\n" for t in THMS)
open("CheckAll.lean","w",encoding="utf-8").write(check)
out=subprocess.run(["lake","env","lean","CheckAll.lean"],capture_output=True,text=True)
report=out.stdout+out.stderr; print(report)
fail=[]
if "sorryAx" in report: fail.append("sorryAx present")
for line in report.splitlines():
    m=re.search(r"depends on axioms:\s*\[(.*)\]",line)
    if m and ({a.strip() for a in m.group(1).split(",") if a.strip()}-ALLOWED): fail.append(line)
n=sum(1 for l in report.splitlines() if "depends on axioms" in l)
if out.returncode!=0 or n<len(THMS): fail.append("incomplete: rc=%d checked=%d/%d"%(out.returncode,n,len(THMS)))
print("="*60)
if fail:
    print("FAIL \u2014 not cleanly kernel-verified:"); [print("  -",f) for f in fail]; sys.exit(1)
else:
    print(f"PASS \u2014 {n}/{len(THMS)} headline theorems kernel-verified across 11 modules; axioms \u2286 {{propext, Classical.choice, Quot.sound}}; no sorry, no native_decide.")
